from pathlib import Path; import sys; 
try:
    from icloud_plugin_mcp.server import main
except ModuleNotFoundError as exc:
    if exc.name not in {'icloud_plugin_mcp', 'icloud_plugin_mcp.server'}:
        raise
    cwd = Path.cwd().resolve()
    root = next((p for p in (cwd, *cwd.parents) if (p / 'src' / 'icloud_plugin_mcp' / 'server.py').exists()), None)
    assert root is not None, 'Could not locate repo root for icloud_plugin_mcp'
    sys.path.insert(0, str(root / 'src'))
    from icloud_plugin_mcp.server import main
main()
